UPDATE dishes SET recipe = '将面粉、鸡蛋、白糖和黄油混合搅拌成均匀细腻的面糊，静置十分钟让面糊充分松弛。格仔饼机预热后刷薄油，倒入适量面糊，盖上盖子烤制五分钟左右至两面金黄酥脆，取出趁热食用口感最佳。' WHERE id = 'hongkong_grid_cake';
UPDATE dishes SET recipe = '虾仁去虾线洗净吸干水分，与笋丁、猪油及调味料拌匀成馅备用。澄面加入沸水快速搅拌揉成半透明面团，分成小份擀成薄圆皮，包入虾馅捏成弯月形褶纹。大火蒸八分钟至虾饺皮呈透明状即可出笼。' WHERE id = 'hongkong_ha_gao';
UPDATE dishes SET recipe = '茄子切厚段、青椒对半切开去籽、豆腐切厚块，分别在中间划口填入调味鲮鱼肉馅压实。平底锅热油，将酿好的三宝依次放入，中小火煎至底面金黄后翻面，煎至鱼肉熟透两面金黄即可装碟。' WHERE id = 'hongkong_jian_yin_san_bao';
UPDATE dishes SET recipe = '鸡翅和鸡肾焯水去血沫捞出，豆腐切大块，萝卜去皮切滚刀块备用。卤水倒入锅中烧开，放入所有食材，小火慢卤四十分钟使食材充分吸收卤水香味，捞出切件摆盘，淋上热卤汁即可食用。' WHERE id = 'hongkong_lou_mei';
UPDATE dishes SET recipe = '面粉、鸡蛋、糖加牛奶搅拌成无颗粒面糊，过筛后摊成薄薄的班戟皮放凉。奶油打发至硬性发泡，芒果去皮切粗条。将打发奶油和芒果条放在饼皮中央，四面折叠包成长方形，冷藏定型半小时后取出食用。' WHERE id = 'hongkong_mango_pancake';
UPDATE dishes SET recipe = '选用粗茶和幼茶按比例混合，用沸水冲泡出浓茶底，将茶袋反复在两个茶壶间高冲低倒拉茶数次，使茶汤更加醇厚丝滑。过滤茶渣后加入淡奶搅拌均匀，根据个人口味加糖调味，冷饮可加入冰块。' WHERE id = 'hongkong_milk_tea';
UPDATE dishes SET recipe = '米浆加少许油调匀，均匀倒在湿润的蒸布上铺薄薄一层，大火猛蒸两分钟至粉皮凝固透亮。用刮板将粉皮从一端卷起成肠状，切段装盘。淋上酱油和甜酱，撒上白芝麻和葱花即可食用。' WHERE id = 'hongkong_pig_intestine_roll';
UPDATE dishes SET recipe = '面粉加糖、鸡蛋和黄油揉成面团发酵至两倍大，分成小份搓圆。另用面粉、黄油和糖做酥皮覆盖在面包面上，用刀划出菠萝纹。烤箱预热一百八十度烤十五分钟至表面金黄，出炉后趁热夹入冰黄油片。' WHERE id = 'hongkong_pineapple_bun_butter';
UPDATE dishes SET recipe = '鲜虾去壳去虾线与猪肉一起剁碎，加盐和胡椒粉调味搅拌上劲，包入云吞皮中捏紧收口。大地鱼干熬制的清汤煮沸调味，放入云吞大火煮至浮起熟透，连汤盛碗撒上葱花和少许麻油即可。' WHERE id = 'hongkong_plain_wonton';
UPDATE dishes SET recipe = '红豆提前浸泡四小时以上，大火煮沸后转小火煮至软烂开花，加入白糖搅匀放凉备用。杯中先放入煮好的红豆，加入炼乳增香，最后堆满碎冰块，搅拌均匀即可饮用，冰凉香甜消暑解渴。' WHERE id = 'hongkong_red_bean_ice';
UPDATE dishes SET recipe = '蒸盘刷薄油，倒入米浆铺薄薄一层，撒上虾仁和叉烧碎，大火猛蒸三分钟至粉皮鼓泡熟透。用刮板从一端将粉皮卷起成长条状，切段装盘，淋上特制酱油和少许芝麻油即可趁热食用。' WHERE id = 'hongkong_rice_noodle_roll';
UPDATE dishes SET recipe = '黑棕鹅洗净去内脏，内腔均匀涂抹五香盐，鹅身外皮用滚水烫过后涂上糖水麦芽水混合液，挂起风干四小时以上。入烤炉先大火烤十五分钟上色，转中火慢烤四十分钟至皮脆肉熟，出炉稍凉后斩件配酸梅酱食用。' WHERE id = 'hongkong_roast_goose';
UPDATE dishes SET recipe = '濑尿虾洗净剪去尖刺沥干水分，入七成热油锅中炸至外壳酥脆变红捞出控油。锅留少许底油，爆香蒜末和红辣椒圈，倒入炸好的濑尿虾，撒入椒盐大火快速翻炒均匀，收干水分即可出锅装盘。' WHERE id = 'hongkong_salt_pepper_mantis';
UPDATE dishes SET recipe = '牛肉逆纹切薄片，用沙嗲酱、生抽和少许淀粉腌制十五分钟入味。面条煮熟捞出沥水备用。热锅炒香洋葱丝，放入牛肉片大火快炒至变色，倒入高汤煮沸，下面条略焖至汤汁浓稠即可盛碗。' WHERE id = 'hongkong_satay_beef_noodle';
UPDATE dishes SET recipe = '虾仁剁成粗虾泥，加蛋清、盐和少许淀粉搅拌上劲，均匀涂抹在吐司面包的一面，撒上白芝麻轻轻按压。入五成热油锅中虾泥面朝下炸至金黄，翻面续炸至吐司酥脆，捞出沥油切三角形装盘。' WHERE id = 'hongkong_shrimp_toast';
UPDATE dishes SET recipe = '猪肉肥三瘦七剁成粗茸，虾仁去虾线切小粒，加香菇碎、生抽和胡椒粉搅拌上劲做馅。面粉擀成薄圆皮，中间放入馅料，用虎口收拢捏成杯状，顶部不封口点缀蟹黄。大火蒸十分钟至熟透即成。' WHERE id = 'hongkong_siu_mai';
UPDATE dishes SET recipe = '五花肉整块焯水定型捞出，表皮用叉子密密扎孔，涂抹白醋和五香盐，放入冰箱风干一夜使皮干燥。烤箱预热至最高温，放入五花肉先高温烤二十分钟使表皮起泡酥脆，转中火续烤三十分钟至肉熟，取出切块食用。' WHERE id = 'hongkong_siu_yuk';
UPDATE dishes SET recipe = '面条煮至八成熟捞出过凉水沥干，豆芽洗净摘去头尾，葱切段备用。热锅宽油大火烧热，放入面条快速翻炒，沿锅边淋入老抽炒匀上色，加入豆芽和葱段大火炒至断生，调味后翻匀出锅。' WHERE id = 'hongkong_soy_sauce_chow_mein';
UPDATE dishes SET recipe = '茄子切两厘米厚段、青椒对半切开去籽、豆腐切三角块，分别在中间填入调味鲮鱼肉馅抹平。平底锅热油，将酿好的食材放入，中小火慢煎至底面金黄后小心翻面，煎至鲮鱼肉熟透即可装盘。' WHERE id = 'hongkong_stuffed_3_treasures';
UPDATE dishes SET recipe = '大排档风味讲究猛火快炒保持锅气。热锅宽油爆香蒜蓉和豆豉，依次烹制豉椒炒蚬、椒盐濑尿虾等经典小炒，每道菜大火快炒不超过两分钟，逐一装盘趁热上桌，配冰冻啤酒最地道。' WHERE id = 'hongkong_tai_pai_dong';
UPDATE dishes SET recipe = '红豆和绿豆提前浸泡四小时，番薯和芋头去皮切滚刀块备用。锅中加足量清水烧开，先放入豆类大火煮沸转中火煮半小时至半熟，加入番薯和芋头块继续煮二十分钟至所有食材软烂，加冰糖调味即可。' WHERE id = 'hongkong_tong_sui';
UPDATE dishes SET recipe = '花蟹洗净去腮切大块，切口处拍少许干淀粉锁住蟹黄。入七成热油锅炸至蟹壳变红捞出。另起锅用大量油爆香蒜蓉至金黄，加入辣椒碎和豆豉炒香，倒入蟹块大火翻炒，撒面包糠炒匀即可出锅。' WHERE id = 'hongkong_typhoon_shelter_crab';
UPDATE dishes SET recipe = '粉丝冷水泡软切短段，鸡蛋打散备用，香菇切细丝。锅中加清水煮沸，放入粉丝和香菇丝煮三分钟至熟透，缓缓淋入蛋液用筷子搅散成蛋花，加入米醋和白胡椒粉调味，勾薄芡盛碗即成。' WHERE id = 'hongkong_wan_zi_xi';
UPDATE dishes SET recipe = '粉丝冷水泡软切段，木耳泡发去蒂切细丝，鸡胸肉煮熟撕成细丝备用。锅中加清水煮沸，放入粉丝、木耳和鸡丝煮熟，淋入蛋液搅成蛋花，加入米醋和胡椒粉调味即成，口感酸辣开胃。' WHERE id = 'hongkong_wanzai_chi';
UPDATE dishes SET recipe = '三黄鸡洗净沥干，一大锅水加姜葱烧沸后放入整鸡，提起三次让鸡腔灌满热水再放回，关火加盖浸泡三十分钟至刚熟。取出立即浸入冰水使鸡皮收紧爽滑，斩件摆盘，蘸沙姜蓉拌花生油和酱油食用。' WHERE id = 'hongkong_white_cut_chicken';
UPDATE dishes SET recipe = '鲜虾云吞提前包好备用，竹升面入沸水锅中煮一分钟即捞出保持弹牙。大地鱼干和虾子熬制的浓汤煮沸调味，碗中放入面条和云吞，浇入滚烫的高汤，撒上葱花和少许韭黄即可上桌。' WHERE id = 'hongkong_wonton_noodle';
UPDATE dishes SET recipe = '西米大火煮至中心只剩小白点时关火加盖焖至全透明，过冷水沥干。芒果一半打成泥一半切小丁，西柚剥出果肉粒。椰浆加芒果泥和少许糖搅匀做底汁，加入西米、芒果丁和西柚肉，冷藏后食用。' WHERE id = 'hongkong_yangzhi_ganlu';
UPDATE dishes SET recipe = '黄豆提前浸泡八小时，用石磨磨成生豆浆，青菜洗净切碎末备用。大锅将豆浆大火煮沸，撇去浮沫后转小火，加入切碎的青菜和干辣椒同煮二十分钟，边煮边搅防止糊底，加盐调味即可盛碗。' WHERE id = 'hubei_enshi_hezha';
UPDATE dishes SET recipe = '面粉加温水揉成光滑面团，擀成大薄片后均匀涂抹一层豆瓣酱，撒上葱花、白芝麻和辣椒碎。从一边卷起成长条再盘成圆饼，轻轻擀平后放入平底锅或烤箱，中小火烙烤至两面焦黄酥脆、层次分明即成。' WHERE id = 'hubei_enshi_tuojia_fan';
UPDATE dishes SET recipe = '面粉加水揉成团后反复揉洗出面筋，洗出的淀粉水静置沉淀四小时以上。倒去上层清水，将淀粉浆舀入刷油的蒸盘摊薄，大火蒸两分钟至鼓泡取出切条。凉皮拌入辣椒油、香醋、蒜水和芝麻酱调匀即食。' WHERE id = 'hubei_ezhou_liangpi';
UPDATE dishes SET recipe = '面粉加沸水烫面揉成软面团醒发半小时。猪肉剁碎与虾仁、香菇丁和笋丁混合，加生抽、盐和香油调成馅料。面团分小份擀成薄皮，包入馅料收口捏成石榴花形，顶部留口露出馅料。大火蒸十五分钟即熟。' WHERE id = 'hubei_huanggang_shaomei';
UPDATE dishes SET recipe = '鱼丸、肉丸分别入沸水氽熟捞出，肉糕提前蒸好切厚片备用。鸡汤倒入砂锅煮沸，放入鱼丸、肉丸和肉糕，中火炖煮十五分钟让三种食材相互融合入味，加盐调味后盛碗，撒葱花点缀即成。' WHERE id = 'hubei_huangpi_sanxian';
UPDATE dishes SET recipe = '面粉加猪油揉成油酥面团做皮，白糖、冰糖碎、芝麻和桂花拌匀做馅料。取适量面皮包入馅料收口，擀成圆饼状，表面刷蛋液撒芝麻。烤箱预热至一百八十度，放入烤盘烤二十分钟至两面金黄酥脆出炉。' WHERE id = 'hubei_huangshi_gangbing';
UPDATE dishes SET recipe = '猪肉和鱼肉分别剁成细茸混合，加蛋清、淀粉和调味料搅拌上劲。鸡蛋摊成完整的大薄蛋皮备用。将调好的肉泥均匀铺在蛋皮上卷紧成卷，盘成龙形摆入盘中大火蒸四十分钟，取出冷却后切薄片装盘。' WHERE id = 'hubei_jingmen_panlongcai';
UPDATE dishes SET recipe = '草鱼取净肉剁成极细的鱼茸，加入蛋清、淀粉和少许盐反复搅拌至鱼茸上劲有弹性。将鱼茸平铺在抹油的蒸盘上，大火蒸二十分钟至熟透凝固。取出放凉后切成长方形薄片，可蒸热或入汤食用。' WHERE id = 'hubei_jingzhou_yumian';
UPDATE dishes SET recipe = '大米和黄豆分别浸泡六小时后混合磨成细腻的米浆，加入葱花、盐和白芝麻搅匀。铁勺放入热油中预热，舀入米浆放入油锅，炸至定型后脱模翻面，继续炸至两面金黄中间酥脆即可捞出沥油。' WHERE id = 'hubei_mianwo';
UPDATE dishes SET recipe = '排骨剁小段冷水下锅焯去血沫捞出洗净，莲藕去皮切成滚刀块泡水防氧化。砂锅中放入排骨和莲藕，加入姜片和料酒，一次性加足清水大火烧开，撇沫后转小火慢炖两小时至汤色浓白、莲藕粉糯，加盐调味。' WHERE id = 'hubei_paigu_outang';
UPDATE dishes SET recipe = '财鱼宰杀去骨取净肉斜刀切薄片，用盐和料酒腌制十分钟。面条煮至八成熟捞出沥干。热锅爆香姜蒜末和干辣椒段，放入鱼片快速滑炒至变色，加入高汤煮沸下面条煮两分钟，调味撒葱花即成。' WHERE id = 'hubei_qianjiang_caiyumian';
UPDATE dishes SET recipe = '财鱼取净肉切薄片，用料酒和淀粉抓匀腌制十分钟去腥。面条煮至八成熟捞出备用。热锅宽油爆香姜蒜和辣椒，下鱼片快炒至变色，倒入高汤煮沸后放入面条，中火煮两分钟至面条入味即可盛碗。' WHERE id = 'hubei_qianjiang_caoyumian';
UPDATE dishes SET recipe = '小龙虾刷洗干净去虾线沥干，热锅宽油爆香干辣椒、花椒和蒜瓣至出香味。放入小龙虾大火翻炒至壳色变红，倒入一整瓶啤酒没过虾身，加酱油和少许糖调味，盖盖中火焖煮十分钟大火收汁即成。' WHERE id = 'hubei_qianjiang_youmen';
UPDATE dishes SET recipe = '碱水面入沸水锅中煮至断生捞出沥干水分，趁热淋上芝麻酱用筷子快速挑拌均匀使每根面条都裹上酱汁。依次加入萝卜丁、酸豆角、葱花和辣椒油，继续拌匀后即可食用，干香浓郁回味无穷。' WHERE id = 'hubei_reganmian';
UPDATE dishes SET recipe = '绿豆粉和鸡蛋加水调成稀薄浆液，舀入平底锅中摊成薄薄的豆皮烙至半熟。铺上一层蒸熟的糯米饭，撒上炒香的猪肉丁、笋丁和香菇丁，将豆皮四面折叠包裹馅料，翻面煎至两面金黄酥脆，切块装盘。' WHERE id = 'hubei_sanxian_doupi';
UPDATE dishes SET recipe = '牛肉切薄片用淀粉抓匀，红薯粉冷水泡软，饺子提前包好煮熟备用。锅中加牛骨汤烧沸，放入牛肉片滑散煮至变色，下入红薯粉煮软，加入煮熟的饺子，调入辣椒油和花椒粉，盛碗撒香菜即成。' WHERE id = 'hubei_shiyan_sanhetang';
UPDATE dishes SET recipe = '猪瘦肉切薄片，用淀粉和少许水调成糊状裹住肉片。锅中水烧至微沸，将肉片逐片下入滑熟捞出沥水。另起锅爆香蒜末和干辣椒，放入滑好的肉片快速翻炒，加少许高汤和盐调味收汁即成。' WHERE id = 'hubei_suizhou_huarou';
UPDATE dishes SET recipe = '鸭子洗净内外擦干水分，用酱油、冰糖和五香八角桂皮等香料涂抹腌制入味，冷藏腌制一天。取出放入锅中加入腌料汁和适量水，小火慢酱一个半小时至鸭肉熟透上色均匀，大火收汁后斩件装盘。' WHERE id = 'hubei_tianmen_jiangya';
UPDATE dishes SET recipe = '武昌鱼洗净在鱼身两侧各划三刀花刀，用少许盐和料酒里外抹匀腌制十分钟，鱼腹塞入姜片和葱段。盘底垫筷子架起鱼身，大火蒸十分钟至鱼眼突出即熟。倒掉盘中蒸汁，淋上蒸鱼豉油，另起油锅烧热油浇在鱼身上激出葱姜香味。' WHERE id = 'hubei_wuchang_yu';
UPDATE dishes SET recipe = '绿豆磨成浆加鸡蛋调匀，在热锅中摊成薄薄的豆皮烙至定型。铺上一层蒸熟的糯米饭压平，均匀撒上炒好的猪肉丁、香菇丁和笋丁馅料。将豆皮四边折叠包裹好，翻面用小火煎至两面金黄焦脆，切成方块装盘。' WHERE id = 'hubei_wuhan_doupi';
UPDATE dishes SET recipe = '鲜活鲫鱼宰杀洗净，入锅加姜片大火熬煮成浓白鱼汤，过滤去骨留汤备用。细粉入沸水烫熟捞入碗中，浇上滚烫的鱼汤，撒上白胡椒粉、葱花和少许虾皮，汤浓味鲜粉滑爽口，是武汉经典早餐。' WHERE id = 'hubei_wuhan_hutangfen';
UPDATE dishes SET recipe = '鸭脖洗净焯水去腥捞出沥干。锅中加足量清水，放入干辣椒、花椒、八角、桂皮和酱油等香料煮开，放入鸭脖大火烧开转小火卤煮四十分钟。关火后让鸭脖浸泡在卤汁中两小时充分入味，捞出即可食用。' WHERE id = 'hubei_wuhan_yabo';
UPDATE dishes SET recipe = '草鱼取净肉用刀背反复捶打成极细的鱼茸，加入蛋清和淀粉朝一个方向搅打上劲至鱼茸有弹性，加盐调味。锅中清水烧至锅底冒小泡但不沸腾，将鱼茸从虎口挤出成丸子用勺刮入水中，小火慢煮至丸子浮起即熟。' WHERE id = 'hubei_wuhan_yuwan';
UPDATE dishes SET recipe = '猪蹄去骨保持完整形状，里外均匀抹上盐和五香粉腌制一天入味。用棉线将猪蹄紧紧缠绕成圆柱形定型，放入卤水中大火煮开转小火卤煮两小时至熟透。取出冷却后拆线切薄片，蘸醋蒜汁食用。' WHERE id = 'hubei_xiangyang_chanti';
UPDATE dishes SET recipe = '牛肉切大块焯水去血沫，另起锅加辣椒、花椒和豆瓣酱炒出红油，放入牛肉加水炖煮两小时至软烂。碱水面煮熟捞入碗中，浇上炖好的牛肉原汤和牛肉块，撒葱花和香菜，麻辣鲜香汤浓面滑。' WHERE id = 'hubei_xiangyang_niumian';
UPDATE dishes SET recipe = '老母鸡宰杀洗净剁大块，冷水下锅焯去血沫捞出冲洗干净。砂锅中放入鸡块，加入姜片、枸杞和红枣，一次性加足清水大火烧开。转最小火加盖慢炖两小时以上至鸡肉酥烂脱骨，汤色金黄，加盐调味即成。' WHERE id = 'hubei_xianning_heshengjitang';
UPDATE dishes SET recipe = '老母鸡洗净切大块焯水去腥捞出，砂锅中放入鸡块加姜片、枸杞和红枣。注入足量清水大火煮沸后撇去浮沫，转小火慢炖两小时至鸡肉酥烂汤色浓黄，加少许盐调味即可，原汁原味营养丰富。' WHERE id = 'hubei_xianning_jitang';
UPDATE dishes SET recipe = '猪肉切片、鲜鱼切块、时令蔬菜切段，分别拌入调味的米粉使每块食材均匀裹粉。三样食材分层摆入竹蒸笼，猪肉在下鱼在中蔬菜在上，大火蒸四十分钟至食材软烂入味、米粉吸收肉汁即可出笼。' WHERE id = 'hubei_xiantao_mianyang_sanzheng';
UPDATE dishes SET recipe = '猪肉切薄片、莲藕去皮切块、白萝卜切块，分别用盐、酱油和米粉拌匀使每块裹上米粉。分层码入蒸笼中大火蒸四十分钟，至猪肉酥烂、莲藕和萝卜软糯入味，出笼撒上葱花即可上桌。' WHERE id = 'hubei_xiantao_sanzheng';
UPDATE dishes SET recipe = '猪肉切片、莲藕切块、豆角切段、南瓜切块，分别拌入调味米粉裹匀。食材分层摆入蒸笼，大火蒸四十分钟至全部软烂入味，米粉吸收了蔬菜和肉的汤汁变得油润鲜香，出笼撒葱花即成。' WHERE id = 'hubei_xiantao_zhengcai';
UPDATE dishes SET recipe = '糯米淘洗干净蒸熟后摊开晾至温热，均匀拌入酒曲压实，中间挖一个小洞便于观察出酒。盖好保温发酵两三天至米粒间渗出甜酒液。取适量酒酿加清水煮沸，撒入干桂花搅匀，即可饮用，清甜醇香。' WHERE id = 'hubei_xiaogan_mijiou';
UPDATE dishes SET recipe = '糯米蒸熟放凉至体温，拌入酒曲装入容器压实发酵两三天成酒酿。取适量酒酿连米带汁倒入锅中，加清水和枸杞煮沸，撒入干桂花搅匀后关火。甜香四溢酒味醇和，可热饮也可放凉后饮用。' WHERE id = 'hubei_xiaogan_mijiu';
UPDATE dishes SET recipe = '大米浸泡后磨成细腻米浆，锅中水烧沸后将米浆缓缓倒入并快速搅拌成浓稠糊状。将糊状物通过漏勺漏入凉开水中凝固成小虾形状的凉虾。捞出盛碗加入红糖熬的糖水和冰块，清凉爽滑是宜昌夏日名小吃。' WHERE id = 'hubei_yichang_ganlan';
UPDATE dishes SET recipe = '白萝卜擦丝加盐腌制十分钟挤去多余水分，拌入辣椒面、花椒粉和少许盐调味做馅。面粉加水揉成面团分成小剂子擀成薄皮，包入萝卜丝馅捏成饺子形状。入六七成热油锅中炸至两面金黄酥脆捞出即食。' WHERE id = 'hubei_yichang_luobo_jiaozi';
UPDATE dishes SET recipe = '黄豆提前泡发用石磨磨成生豆浆，大火煮沸后过滤豆渣。豆浆回锅保持微沸，缓慢冲入化开的石膏水轻轻搅动，静置凝固成豆花。盛入碗中加入辣椒油、花椒面、芝麻和葱花等调料，麻辣鲜香口感细嫩。' WHERE id = 'hubei_yichang_xiadouhua';
UPDATE dishes SET recipe = '鸭子洗净去内脏，用盐、花椒和五香粉里外涂抹腌制两天入味。取出挂通风处风干表面水分，再涂抹酱油上色。用谷壳和茶叶熏制至表皮深红出油，最后入烤箱低温慢烤至干香，斩件食用麻辣劲道。' WHERE id = 'hunan_changde_jiangbanya';
UPDATE dishes SET recipe = '牛肉切薄片用生抽和淀粉腌制十分钟，干米粉入沸水烫软捞入碗中备用。热锅宽油爆香干辣椒和花椒粒，放入牛肉片大火翻炒至变色，加骨汤煮沸浇在米粉上，撒葱花和少许酸豆角拌匀即食。' WHERE id = 'hunan_changde_mifen';
UPDATE dishes SET recipe = '鸭脖洗净冷水下锅焯去血沫捞出沥干。锅中加水放入大量干辣椒、花椒、八角、桂皮和老抽煮开成卤汁，放入鸭脖大火煮沸转小火卤煮三十分钟。关火浸泡两小时让鸭脖充分吸收麻辣卤汁后捞出食用。' WHERE id = 'hunan_changsha_juewei_yabo';
UPDATE dishes SET recipe = '小龙虾刷洗干净剪去虾头尖部去虾线沥干。热锅宽油爆香大量干辣椒、花椒和蒜瓣，放入小龙虾大火猛炒至壳色通红。加入新鲜紫苏叶和少量清水，盖盖焖煮十分钟至虾肉入味，大火收汁装盘即成。' WHERE id = 'hunan_changsha_kouweixia';
UPDATE dishes SET recipe = '螃蟹刷洗干净去腮切大块，切口处拍少许淀粉。热锅宽油爆香干辣椒、花椒和蒜末，放入蟹块大火翻炒至蟹壳变红。加入紫苏叶和少许清水，中火焖煮五分钟让蟹肉吸收香辣味，大火收汁即成。' WHERE id = 'hunan_changsha_kouweixie';
UPDATE dishes SET recipe = '肉丝用生抽和淀粉腌制十分钟，干米粉入沸水烫软捞出盛碗备用。热锅宽油炒香肉丝和辣椒做成码子浇在米粉上，冲入滚烫的骨汤，撒上葱花和少许剁辣椒，拌匀即可食用，汤鲜粉滑辣味十足。' WHERE id = 'hunan_changsha_mifen';
UPDATE dishes SET recipe = '糯米粉加温水揉成柔软面团分成小份搓圆按扁成小饼。锅中放少许油，下红糖和白糖小火熬化成浓稠糖油。放入糯米粑粑小火慢煎，不断翻面使两面均匀裹上糖油，煎至粑粑鼓起呈焦糖色、外脆内糯即成。' WHERE id = 'hunan_changsha_tangyou_baba';
UPDATE dishes SET recipe = '糯米加水浸泡后磨成粉再揉成小圆饼备用。锅中放入红糖和白糖加少许水小火熬化成浓稠糖油，放入糯米粑粑用小火慢慢煎制。不断翻面让粑粑两面均匀裹上焦糖色糖油，煎至外皮酥脆内里软糯即可出锅。' WHERE id = 'hunan_changsha_tangyouba';
UPDATE dishes SET recipe = '五花肉切薄片，青辣椒切斜段，蒜切片备用。热锅不放油直接下五花肉片中小火煸炒至出油微焦，推至锅边。用猪油爆香蒜片和豆豉，放入青辣椒大火翻炒至断生，与肉片混合炒匀调味出锅。' WHERE id = 'hunan_changsha_xiaochaorou';
UPDATE dishes SET recipe = '鲢鱼宰杀洗净入锅加姜片熬煮成浓白鱼汤，过滤去骨加辣椒和豆膏调味。干米粉入沸水烫软捞入大碗，舀入滚烫的鱼汤没过米粉，撒上葱花和少许山胡椒，汤鲜味辣米粉爽滑，是郴州名粉。' WHERE id = 'hunan_chenzhou_qifengdu_yufen';
UPDATE dishes SET recipe = '鲢鱼宰杀洗净入锅加姜片大火熬成浓白鱼汤，捞出鱼骨过滤留汤。鱼汤回锅加干辣椒和豆膏煮出辣味。干米粉入沸水烫熟捞出盛碗，浇上滚烫的鱼汤，撒上葱花和少许山胡椒粉，鲜辣开胃粉滑汤浓。' WHERE id = 'hunan_chenzhou_yufen';
UPDATE dishes SET recipe = '豆腐切块放入用冬笋、香菇和浏阳豆豉发酵而成的特制臭卤中浸泡一天至入味发臭。捞出沥干入七成热油锅中炸至外皮焦酥内里嫩滑。捞出后在每块豆腐上戳洞，灌入用辣椒、蒜末和香菜调制的料汁即可。' WHERE id = 'hunan_chou_doufu';
UPDATE dishes SET recipe = '鲢鱼头从下巴处对半劈开洗净沥干，鱼肉面朝上摆入盘中。均匀铺上剁椒酱、豆豉和蒜末，淋少许料酒去腥。大火蒸十五分钟至鱼头熟透，倒去多余汤汁，淋上蒸鱼豉油，另起锅烧热油浇在鱼头上激出香味。' WHERE id = 'hunan_dujiao_yutou';
UPDATE dishes SET recipe = '草鱼从背部剖开去内脏洗净，里外抹盐腌制一天后挂起风干。在鱼身涂抹酱油、辣椒面和花椒粉的混合调料，用谷壳和茶叶熏制至表面深红。食用时取适量上锅蒸十五分钟，切片摆盘，肉质紧实咸香。' WHERE id = 'hunan_hengyang_jiangbanyu';
UPDATE dishes SET recipe = '鲜活鱼宰杀洗净入锅加姜片大火熬煮成浓白鱼汤，捞出鱼骨过滤。鱼汤回锅加辣椒面调味。干米粉入沸水烫软捞入碗中，浇入滚烫的鱼汤，撒上姜末、蒜末和葱花，鲜辣醇厚米粉爽滑。' WHERE id = 'hunan_hengyang_yufen';
UPDATE dishes SET recipe = '稻花鱼洗净去内脏不去鳞，里外抹匀粗盐腌制半天沥去水分。坛中底部撒一层糯米和辣椒，放一层鱼，如此反复层层铺满。密封坛口腌制三至六个月至鱼肉发酵入味，取出即可生食或蒸食，酸辣鲜香。' WHERE id = 'hunan_huaihua_tanzuyu';
UPDATE dishes SET recipe = '稻花鱼洗净去内脏，用粗盐里外抹匀腌制半天控干水分。取干净坛子，一层拌好辣椒的糯米铺底，一层鱼码上，层层叠满压实密封。腌制数月发酵产生独特酸香味，取出切片或蒸食，风味浓郁。' WHERE id = 'hunan_huaihua_yanyu';
UPDATE dishes SET recipe = '鸭肉剁成小块焯水去血沫捞出沥干。热锅宽油爆香姜蒜末和大量干辣椒，放入鸭块大火翻炒至鸭肉出油收缩。加入酱油和适量清水没过鸭肉，大火烧开转中小火焖煮四十分钟至鸭肉酥烂入味收汁即成。' WHERE id = 'hunan_huaihua_zhijiangya';
UPDATE dishes SET recipe = '小龙虾刷洗干净去虾线沥干水分备用。热锅宽油爆香大量干辣椒、花椒和蒜瓣出香味，放入小龙虾大火翻炒至壳色变红。加入新鲜紫苏叶和适量清水，盖盖焖煮十分钟入味，大火收汁装盘，麻辣鲜香。' WHERE id = 'hunan_kouwei_xia';
UPDATE dishes SET recipe = '五花肉切薄片，本地青辣椒切斜段，蒜切片备用。热锅不放油下五花肉中小火煸炒至出油微焦，推至锅边。用锅中猪油爆香蒜片和豆豉，放入青辣椒大火翻炒至断生微焦，与肉片混合翻匀调味出锅。' WHERE id = 'hunan_lajiao_chaorou';
UPDATE dishes SET recipe = '腊肉切薄片、干鱼切小块、豆腐切厚片，分别拌入辣椒面和调味米粉裹匀。食材分层摆入竹蒸笼，大火蒸三十分钟至腊肉出油、干鱼软化、豆腐入味。出笼后食材原汁原味渗入米粉中，鲜辣下饭。' WHERE id = 'hunan_liuyang_zhengcai';
UPDATE dishes SET recipe = '新鲜牛血切块、牛肉切薄片、牛肚切条分别焯水去腥。锅中加牛骨汤烧沸，放入干辣椒和姜片煮出辣味，下入牛血、牛肉和牛肚大火煮至熟透，调入盐和山胡椒粉，盛碗撒香菜即成。' WHERE id = 'hunan_loudi_sanhetang';
UPDATE dishes SET recipe = '牛血切块、牛肉切片焯水去腥，红薯粉冷水泡软。锅中加骨汤烧沸放入干辣椒和山胡椒煮出独特香味，下入牛血和牛肉煮熟，再加红薯粉煮软入味。盛碗撒葱花，汤底麻辣鲜香带有山胡椒的特殊芳香。' WHERE id = 'hunan_loudi_xinhua_sanhetang';
UPDATE dishes SET recipe = '五花肉切三厘米见方的大块焯水去血沫捞出。锅中放冰糖小火炒至焦糖色起大泡，放入肉块快速翻炒均匀上色。加入老抽、干辣椒、八角和桂皮，加热水没过肉面大火烧开，转小火慢炖一小时至肉酥烂汤浓稠。' WHERE id = 'hunan_maoshi_hongshaorou';
UPDATE dishes SET recipe = '牛肉切薄片用生抽和淀粉腌制，干米粉入沸水烫软捞出盛碗。热锅炒香牛肉片加干辣椒做成码子，再加入酸豆角翻炒出香。将码子浇在米粉上，冲入滚烫骨汤，撒葱花拌匀，酸辣鲜香。' WHERE id = 'hunan_shaoyang_mifen';
UPDATE dishes SET recipe = '新鲜猪血与老豆腐捏碎混合均匀，加入辣椒碎和猪肉末揉成拳头大小的丸子。放在通风处晾干表面水分，再用谷壳和木屑熏制至表面干燥变黑。食用时取出蒸二十分钟至熟透，切片摆盘，风味独特咸香。' WHERE id = 'hunan_shaoyang_zhuxue_wanzi';
UPDATE dishes SET recipe = '猪血与豆腐混合捏碎，加入辣椒面和五花肉末充分揉匀，捏成丸子形状晾干表面。用柏树枝和谷壳慢慢熏制至表皮变黑干燥。食用时蒸二十分钟切片，猪血和豆腐的混合口感紧实，辣椒和烟熏味浓郁。' WHERE id = 'hunan_shaoyang_zhuxuewanzi';
UPDATE dishes SET recipe = '糯米粉加白糖、桂花和少许薄荷水揉成光滑面团，擀成薄片后切成细长条状整齐码入蒸笼。大火蒸十五分钟至熟透取出，表面撒上薄荷粉和少许白糖，放凉后口感韧滑带有桂花和薄荷的清香。' WHERE id = 'hunan_xiangtan_dengxingao';
UPDATE dishes SET recipe = '五花肉整块煮至七成熟捞出，趁热在肉皮上抹老抽上色。入热油锅将肉皮面炸至起泡呈虎皮色捞出切厚片。碗底铺泡发的梅干菜，肉片皮朝下整齐码好，淋酱油放冰糖大火蒸一小时，取出倒扣在盘中即成。' WHERE id = 'hunan_xiangtan_kourou';
UPDATE dishes SET recipe = '五花肉切长条用盐和花椒粒反复揉搓腌制五天，取出挂在通风处晾干表面水分。用柏树枝和橘子皮慢慢熏制数小时至肉表面金黄渗出油脂。食用时取适量切薄片上锅蒸二十分钟，烟香扑鼻肥而不腻。' WHERE id = 'hunan_xiangxi_larou';
UPDATE dishes SET recipe = '鸡爪剪去指甲洗净，入加姜片和料酒的沸水中煮十分钟至熟透，捞出过冰水使口感爽脆去骨。泡椒连汁倒入容器，加入白醋、蒜片和凉开水调成泡菜水，放入鸡爪浸泡冷藏一天即可食用，酸辣爽脆。' WHERE id = 'hunan_xiangxi_paogu';
UPDATE dishes SET recipe = '鸡爪剪去指甲洗净煮熟过冰水，沥干后去骨保持形状完整。泡椒切碎连汁倒入碗中，加入白醋、蒜末和少许凉开水调成泡菜水。将鸡爪放入泡菜水中浸泡，密封冷藏一天至入味，取出食用酸辣爽脆。' WHERE id = 'hunan_xiangxi_paojiao_fengzhua';
UPDATE dishes SET recipe = '将茶叶、炒花生、白芝麻、绿豆和大米放入擂钵中，用擂棍反复捣碾成细腻的糊状物。冲入沸水边冲边搅拌均匀至汤色浓稠，加少许盐调味即可饮用。擂茶香浓营养，是益阳客家人待客的传统饮品。' WHERE id = 'hunan_yiyang_leicha';
UPDATE dishes SET recipe = '鸭肉剁小块，新鲜鸭血加少许醋和盐搅匀防凝固。热锅宽油爆香姜蒜末和干辣椒，放入鸭肉大火翻炒至出油收缩变色。趁热将鸭血均匀淋在鸭肉上快速翻炒，使鸭血凝固裹住每块鸭肉，加米酒翻匀出锅。' WHERE id = 'hunan_yongzhou_xueya';
UPDATE dishes SET recipe = '莲藕去皮切成三毫米厚的薄片，两片中间夹入调味猪肉馅轻轻按压合拢。面粉加鸡蛋和少许水调成浓稠面糊。将藕夹裹上面糊入六成热油锅中炸至定型，捞出复炸一次至外壳金黄酥脆，沥油装盘。' WHERE id = 'hunan_yueyang_dongting_heduojia';
UPDATE dishes SET recipe = '洞庭湖银鱼洗净沥干水分，鸡蛋打入碗中加少许盐打散，放入银鱼和葱姜末搅匀。热锅宽油烧至七成热，倒入银鱼蛋液大火翻炒至蛋液凝固成大块，保持银鱼完整鲜嫩即可装盘，口感鲜美嫩滑。' WHERE id = 'hunan_yueyang_dongting_yinyu';
UPDATE dishes SET recipe = '鲢鱼头从下巴对半劈开洗净沥干，鱼肉面朝上摆入深盘中。均匀铺上酱椒碎、豆豉和蒜末，淋少许料酒。大火蒸十五分钟至鱼头熟透筷子能轻松插入，淋上蒸鱼豉油，另烧热油浇上激出香味即成。' WHERE id = 'hunan_yueyang_tonggu_yu';
UPDATE dishes SET recipe = '腊肉切薄片，老豆腐切三角块，白萝卜切厚片备用。热锅少许油炒香干辣椒和花椒粒，放入腊肉片煸炒出油至边缘微卷。加入豆腐和萝卜翻炒均匀，倒入适量清水大火烧开转中火焖煮十五分钟至萝卜软烂入味。' WHERE id = 'hunan_zhangjiajie_sanxiaguo';
UPDATE dishes SET recipe = '干米粉提前泡软沥干水分，鸡蛋打散备用。热锅宽油大火烧热，先倒入蛋液快速炒散成蛋碎盛出。锅中再加油烧热，放入米粉大火翻炒至米粉松散不粘连，加入炒蛋、豆芽和辣椒丝翻炒均匀调味出锅。' WHERE id = 'hunan_zhuzhou_chaofen';
UPDATE dishes SET recipe = '老豆腐切大块在中间用勺子挖出凹槽，填入用猪肉末、香菇碎和葱花调好的馅料抹平。平底锅热油将酿豆腐馅料面朝下煎至定型金黄，翻面加高汤和酱油，中小火焖煮十分钟至入味收汁装盘。' WHERE id = 'hunan_zhuzhou_yanling_zhaobian';
UPDATE dishes SET recipe = '面粉加猪油、白糖和少许水揉成油酥面团醒半小时，分成小份包入白芝麻和糖桂花调成的馅料收口。擀成椭圆形薄饼，表面刷水撒白芝麻。烤箱预热至二百度，放入烤十五分钟至层次分明、两面金黄酥脆出炉。' WHERE id = 'jiangsu_changzhou_tianmian';
UPDATE dishes SET recipe = '天目湖鲢鱼头洗净对半劈开沥干，入热油锅煎至两面微黄去腥。转入砂锅加入嫩豆腐块、枸杞和姜片，注入足量清水大火烧开。转小火慢炖一小时以上至汤色浓白如乳，加盐和白胡椒调味即成。' WHERE id = 'jiangsu_changzhou_yuantou';
UPDATE dishes SET recipe = '阳澄湖大闸蟹用刷子刷洗干净，用棉线绑好防止蒸时挣扎掉腿。蟹肚朝上放入蒸锅，每只蟹上放一片姜去寒。大火蒸十五分钟至蟹壳完全变红取出，配姜丝浸镇江香醋的蘸汁食用，蟹黄饱满鲜甜。' WHERE id = 'jiangsu_dazhaxie';
UPDATE dishes SET recipe = '方豆腐干先片成薄片再切成如火柴棍般极细的丝，入沸水反复焯烫三次去豆腥味捞出。鸡汤煮沸放入干丝、河虾仁和嫩笋片，小火慢煮二十分钟至干丝充分吸满鸡汤鲜味，加盐调味即可上桌。' WHERE id = 'jiangsu_dazhu_gansi';
UPDATE dishes SET recipe = '猪肉剁成细茸加生抽和姜水搅拌上劲，加入切碎的猪皮冻拌匀成馅使蒸后出汤汁。面粉加水揉成面团擀成极薄的皮，包入馅料收口捏成汤包形状。大火蒸十分钟至皮薄透明汤汁充盈，配姜丝醋食用。' WHERE id = 'jiangsu_huaiyang_shaomai';
UPDATE dishes SET recipe = '活鳝鱼烫杀取脊背净肉切长段，用盐和淀粉反复揉搓去粘液洗净。热锅宽油爆香蒜片，放入鳝段大火快炒至鳝肉卷曲。加入老抽、黄酒和少许白糖翻匀，加少量水焖煮两分钟收汁，肉质软嫩鲜香。' WHERE id = 'jiangsu_huaiyang_shizitou';
UPDATE dishes SET recipe = '鸭子洗净去内脏，用炒过的花椒盐里外揉搓腌制入味，冷藏腌两天后取出挂起风干表面水分。用柏树枝和锯末熏制至表皮微黄出油，再挂通风处晾至肉质紧实有弹性。食用时切薄片，腊香浓郁。' WHERE id = 'jiangsu_nanjing_dingling';
UPDATE dishes SET recipe = '嫩豆腐切成小块入沸水中烫透去腥捞入碗中。碗中撒上泡发的虾米和切碎的榨菜增加鲜味和口感，淋上一勺红艳艳的辣椒油，点缀洗净的香菜叶。食用前轻轻拌匀，豆腐嫩滑配料鲜香。' WHERE id = 'jiangsu_nanjing_doufu_nao';
UPDATE dishes SET recipe = '猪肉剁碎加姜末、生抽和葱花调成馅料，面粉加水揉成面团擀成薄皮包成饺子。平底锅刷薄油摆入饺子，中火煎至底部微黄，倒入没过饺子底部三分之一的面粉水，盖盖焖煎至水干底部金黄酥脆即成。' WHERE id = 'jiangsu_nanjing_guotie';
UPDATE dishes SET recipe = '莲藕去皮切段，糯米提前浸泡四小时后逐粒塞入藕孔中压实用牙签封口。锅中放入藕段加水没过，加入蜂蜜和冰糖大火煮沸转小火慢煮两小时至莲藕酥软糯米黏糯。取出切厚片淋上桂花蜜汁即可食用。' WHERE id = 'jiangsu_nanjing_mafu_tang';
UPDATE dishes SET recipe = '面条入沸水煮至八成熟，加入泡发切块的皮肚、猪肝薄片和青菜叶同煮。调入少许辣椒油、盐和胡椒粉，大火煮至猪肝变色熟透、青菜断生，连汤带料盛入大碗中，南京人最爱的家常小煮面即成。' WHERE id = 'jiangsu_nanjing_mian';
UPDATE dishes SET recipe = '鸭子洗净用炒热的花椒盐里外揉搓腌制四小时入味。取出放入加有八角和葱姜的清水中，大火煮沸转小火煮三十分钟至刚熟。捞出自然冷却后斩件装盘，鸭皮洁白肉质鲜嫩，蘸姜醋汁食用咸香适口。' WHERE id = 'jiangsu_nanjing_yanshui_ya';
UPDATE dishes SET recipe = '鸭子洗净里外抹上炒热的花椒盐腌制四小时。放入加了八角、葱姜的清水中大火煮沸，转小火浸煮三十分钟至刚熟捞出。冷却后斩件摆盘，皮白肉嫩骨边微红，配姜丝蘸香醋食用，南京经典名菜。' WHERE id = 'jiangsu_nanjing_yanshuiya';
UPDATE dishes SET recipe = '鸭血切小块，粉丝冷水泡软，鸭肝鸭肠焯水后切薄片，豆腐果对半切开。锅中加鸭骨熬制的浓汤烧沸，放入粉丝和豆腐果煮两分钟，再下鸭血、鸭肝和鸭肠烫熟，加盐和白胡椒调味盛碗撒香菜。' WHERE id = 'jiangsu_nanjing_yaxue_fentang';
UPDATE dishes SET recipe = '五花肉细切粗剁成石榴粒大小，加入蟹粉、荸荠碎和姜水搅拌上劲至肉馅有粘性。做成拳头大的肉丸放入砂锅，注入清澈鸡汤没过肉丸。大火烧开转最小火慢炖两小时至丸子酥烂入口即化，汤鲜味美。' WHERE id = 'jiangsu_shizi_tou';
UPDATE dishes SET recipe = '鳜鱼去骨留头尾鱼身改十字花刀拍干淀粉，入七成热油锅炸至鱼肉翻卷成松球状金黄定型捞出摆盘。另起锅调番茄酱、糖、醋和少许水熬成红亮的糖醋汁浇在鱼身上，撒上炸香的松子点缀，形似松鼠。' WHERE id = 'jiangsu_shongshu_guiyu';
UPDATE dishes SET recipe = '面条入沸水煮熟捞出沥干装碗。猪骨和鳝鱼骨熬制的白汤加少许酒酿调出独特清鲜底味，大火烧沸。焖肉提前卤好切成厚片铺在面上，浇入滚烫的白汤，面条吸汁入味汤清鲜美肉酥烂，苏州时令名面。' WHERE id = 'jiangsu_suzhou_fengzhen_mian';
UPDATE dishes SET recipe = '面条入沸水煮至弹牙捞出装碗。猪骨浓汤加酒酿调味煮沸，焖肉提前用酱油和香料炖至酥烂切成厚片。将焖肉铺在面上，浇入滚烫的骨汤撒上葱花，面条吸足汤汁鲜美滑爽，焖肉入口即化。' WHERE id = 'jiangsu_suzhou_fengzheng_mian';
UPDATE dishes SET recipe = '藏书山羊宰杀洗净切大块，冷水下锅加姜片和料酒大火焯去膻味和血沫捞出。另起锅加足量清水放入羊肉大火烧开，转小火加盖慢炖两小时以上至羊肉酥烂脱骨、汤色乳白。加盐调味撒蒜叶即成。' WHERE id = 'jiangsu_suzhou_shuangma';
UPDATE dishes SET recipe = '全脂牛奶小火加热后倒入碗中静置冷却，表面凝结第一层奶皮。沿碗边挑开小口将牛奶倒出与蛋清和白糖搅匀过筛。再沿小口倒回碗中让奶皮浮起覆盖表面，上锅蒸十五分钟凝固结出第二层奶皮，冷藏食用。' WHERE id = 'jiangsu_suzhou_shuangpi_shaomai';
UPDATE dishes SET recipe = '蟹粉与猪肉末混合加生抽调味，再加入切碎的猪皮冻拌匀冷藏使馅料凝固好包。面粉加水揉成面团擀成极薄的皮，包入馅料捏出十八个以上的褶子收口。大火蒸八分钟取出，皮薄如纸汤汁丰富，蘸姜丝醋食用。' WHERE id = 'jiangsu_suzhou_xiefen_tangbao';
UPDATE dishes SET recipe = '内酯豆腐先片成薄片再切成细如头发的丝，放入清水中轻轻散开防止粘连。清鸡汤煮沸调味，轻轻放入豆腐丝、香菇丝、笋丝和火腿丝，小火微沸煮三分钟使食材入味融合，盛入汤碗中刀工精美汤鲜味醇。' WHERE id = 'jiangsu_wensi_doufu';
UPDATE dishes SET recipe = '猪肋排剁成五厘米长段焯水去血沫捞出。锅中放冰糖小火炒至枣红色起泡，放入排骨快速翻炒上色。加入老抽、黄酒和适量热水没过排骨，大火烧开转小火焖煮四十分钟至肉酥烂脱骨，大火收汁至浓稠发亮。' WHERE id = 'jiangsu_wuxi_paigu';
UPDATE dishes SET recipe = '猪排骨焯水去血沫捞出。锅中放入大量冰糖小火熬化炒至焦糖色，放入排骨翻炒均匀上色。加入酱油和黄酒，倒入适量热水大火烧开转小火慢炖一小时至排骨酥烂，汤汁浓稠挂在排骨上甜香入味即成。' WHERE id = 'jiangsu_wuxi_tangpai';
UPDATE dishes SET recipe = '猪肉剁成细茸加生抽调味，猪皮冻切碎混入肉馅中，加入少许白糖提鲜。面粉加水揉成面团擀成薄皮，包入馅料捏出细密褶子收口。大火蒸八分钟取出，咬开小口先吸汤汁再吃馅，皮薄汁多甜鲜可口。' WHERE id = 'jiangsu_wuxi_xiaolongbao';
UPDATE dishes SET recipe = '土鸡剁块焯水去血沫。热锅炒香干辣椒和花椒，放入鸡块大火翻炒至表面微焦，加酱油和料酒上色调味。加入适量清水大火烧开转中火焖煮，锅边贴一圈发酵好的面饼，盖盖焖十五分钟至饼熟鸡烂汤浓即成。' WHERE id = 'jiangsu_xuzhou_diguoji';
UPDATE dishes SET recipe = '隔夜米饭打散拨松，鸡蛋打散备用。热锅宽油大火烧至冒烟，先倒入蛋液快速炒散成蛋碎，随即倒入米饭大火翻炒至粒粒分明。加入虾仁丁和火腿丁翻炒均匀，放入青豆和少许盐调味炒匀即可出锅。' WHERE id = 'jiangsu_yangzhou_chaofan';
UPDATE dishes SET recipe = '方豆腐干先片成薄如纸张的片再切成极细的丝，入沸水焯烫三次去豆腥。老母鸡熬制的清汤煮沸调味，放入干丝、河虾仁和嫩笋片，小火慢煮二十分钟至干丝充分吸收鸡汤鲜味，盛碗即可上桌。' WHERE id = 'jiangsu_yangzhou_gansi_tang';
UPDATE dishes SET recipe = '嫩豆腐先片成薄片再切成细如发丝的丝入清水散开。清鸡汤煮沸调味，轻轻推入豆腐丝不搅动，加入香菇丝、笋丝和火腿丝同煮三分钟至入味。此菜考验刀工，豆腐丝细如毛发在汤中如云似雾，鲜美无比。' WHERE id = 'jiangsu_yangzhou_wensi_doufu';
UPDATE dishes SET recipe = '大锅宽水煮沸放入一只小锅盖浮在水面上压住翻滚的面条，使面条在锅盖下受热均匀煮至弹牙捞出。碗中先放酱油和猪油，放入煮好的面条拌匀让油脂包裹每根面条，配烫熟的青菜即成镇江特色面食。' WHERE id = 'jiangsu_zhenjiang_guogai_mian';
UPDATE dishes SET recipe = '猪蹄去骨保持完整，用盐和少许硝腌制一天使其肉质紧实粉红。取出放入加姜片的清水中大火煮沸转小火煮两小时至熟透。捞出放入方形容器压实冷却定型，切薄片装盘配姜丝和镇江香醋食用。' WHERE id = 'jiangsu_zhenjiang_yaorou';
UPDATE dishes SET recipe = '崇仁麻鸡洗净沥干水分，一大锅水加姜片和葱段烧沸后放入整鸡。大火煮沸后转小火浸煮二十分钟至刚熟，捞出立即浸入冰水使鸡皮收紧。斩件装盘淋上由酱油、姜蓉和花生油调成的蘸汁，皮爽肉滑原汁原味。' WHERE id = 'jiangxi_chongren_maji';
UPDATE dishes SET recipe = '糯米蒸熟后摊开在阴凉处晾干成冻米粒。冻米入五六成热油锅中炸至膨松变白捞出控油。另起锅放入白糖和少许水熬成能拉丝的糖浆，倒入炸好的冻米、白芝麻和花生碎快速翻拌均匀，趁热倒入模具压实切块。' WHERE id = 'jiangxi_fengcheng_dongmi_tang';
UPDATE dishes SET recipe = '五花肉切厚片用酱油、料酒和少许腐乳汁腌制半小时入味，取出均匀裹上一层调味米粉。红薯去皮切大块垫在蒸碗底部，裹好粉的肉片皮朝下码在上面。大火蒸四十分钟至肉酥烂米粉软糯油润，出锅撒辣椒粉和葱花。' WHERE id = 'jiangxi_fenzhengrou';
UPDATE dishes SET recipe = '干米粉入沸水中烫至微软捞出沥干盛入碗中。猪骨加姜片熬制的浓白骨汤大火烧沸调味，舀入滚烫的骨汤没过米粉。加上一勺辣椒酱和葱花，米粉在热汤中继续泡软吸味，汤鲜粉滑辣味十足开胃。' WHERE id = 'jiangxi_fuzhou_paofen';
UPDATE dishes SET recipe = '草鱼去骨取肉斜刀切薄片，用盐、料酒和淀粉抓匀腌制十分钟。鱼片入六成热油锅中炸至金黄定型捞出控油。锅留底油爆香蒜末和干辣椒段，倒入鱼片大火快炒，沿锅边烹入香醋翻匀出锅，外酥内嫩酸辣开胃。' WHERE id = 'jiangxi_gannan_xiaochaoyu';
UPDATE dishes SET recipe = '粳米浸泡后磨成米浆，加入食用碱水和黄栀子汁揉成金黄色面团。上锅大火蒸半小时至熟透取出反复揉搓至面团光滑有韧性。搓成长条切成小块，可切片炒食或煮汤食用，色泽金黄口感韧滑带有独特碱香。' WHERE id = 'jiangxi_ganzhou_huangyuan_miguo';
UPDATE dishes SET recipe = '绿茶茶叶、白芝麻、炒花生仁和新鲜薄荷叶放入擂钵中，用擂棍反复捣碾研磨成细腻糊状。冲入沸水边冲边搅拌至汤色碧绿浓稠，加少许细盐调味即可饮用。擂茶香浓回甘营养丰富，是客家人每日必饮的传统保健茶。' WHERE id = 'jiangxi_ganzhou_kejia_leicha';
